public class EqualityDemo {
    public static void main(String[] args) {

        // String comparison
        String a = new String("hello");
        String b = new String("hello");

        System.out.println(a == b);       // false — different objects in memory
        System.out.println(a.equals(b));  // true  — same content

        // String pool case
        String x = "Java";
        String y = "Java";
        System.out.println(x == y);       // true — both point to same pool object
        System.out.println(x.equals(y)); // true — same content

        // Integer comparison
        Integer p = new Integer(100);
        Integer q = new Integer(100);
        System.out.println(p == q);       // false — different objects
        System.out.println(p.equals(q)); // true  — same value

        // Primitives
        int m = 5, n = 5;
        System.out.println(m == n);       // true — primitives compared by value
    }
}

public class FinalDemo {

    // final variable — cannot reassign
    static final double PI = 3.14159;

    // final method — cannot override
    public final void display() {
        System.out.println("I cannot be overridden");
    }

    public static void main(String[] args) {

        // finally block
        try {
            int result = 10 / 2;
            System.out.println("Result: " + result);
        } catch (ArithmeticException e) {
            System.out.println("Exception caught");
        } finally {
            System.out.println("finally always runs!"); // always executes
        }

        // final local variable
        final int x = 10;
        // x = 20; // compile error — cannot reassign

        System.out.println("PI = " + PI);
    }

    // finalize — deprecated, don't use in modern code
    @Override
    protected void finalize() throws Throwable {
        System.out.println("Object being garbage collected");
        super.finalize();
    }
}

public class StringDemo {
    public static void main(String[] args) {

        // String — immutable
        String s = "Hello";
        s = s + " World"; // A NEW object is created each time
        System.out.println(s); // Hello World

        // StringBuilder — mutable, not thread-safe, fast
        StringBuilder sb = new StringBuilder("Hello");
        sb.append(" World");
        sb.insert(5, ",");
        sb.reverse();
        System.out.println(sb.toString()); // dlroW ,olleH

        // StringBuffer — mutable, thread-safe, slightly slower
        StringBuffer sbf = new StringBuffer("Java");
        sbf.append(" Programming");
        System.out.println(sbf.toString()); // Java Programming

        // Performance difference visible in a loop
        long start = System.currentTimeMillis();
        String result = "";
        for (int i = 0; i < 10000; i++) {
            result += i; // SLOW — creates 10000 new String objects
        }
        System.out.println("String loop: " + (System.currentTimeMillis() - start) + "ms");

        start = System.currentTimeMillis();
        StringBuilder sbLoop = new StringBuilder();
        for (int i = 0; i < 10000; i++) {
            sbLoop.append(i); // FAST — modifies same object
        }
        System.out.println("StringBuilder loop: " + (System.currentTimeMillis() - start) + "ms");
    }
}

