// Overriding — subclass redefines parent method
class Animal {
    public void speak() {
        System.out.println("Animal makes a sound");
    }
}

class Dog extends Animal {
    @Override
    public void speak() {
        System.out.println("Dog barks");
    }
}

public class PolyDemo {
    public static void main(String[] args) {
        Calculator calc = new Calculator();
        System.out.println(calc.add(2, 3));       // 5  (int version)
        System.out.println(calc.add(2.5, 3.5));   // 6.0 (double version)
        System.out.println(calc.add(1, 2, 3));    // 6  (3-param version)

        Animal a = new Dog(); // runtime polymorphism
        a.speak(); // prints: Dog barks (Dog's overridden version)
    }
}

import java.io.*;

public class ExceptionDemo {

    // Must declare checked exception with 'throws'
    public static void readFile(String path) throws IOException {
        FileReader fr = new FileReader(path); // throws checked IOException
        fr.close();
    }

    public static void main(String[] args) {

        // Handling a checked exception
        try {
            readFile("missing.txt");
        } catch (IOException e) {
            System.out.println("Caught checked exception: " + e.getMessage());
        }

        // Unchecked exception — no compile error if not handled
        String s = null;
        try {
            System.out.println(s.length()); // NullPointerException at runtime
        } catch (NullPointerException e) {
            System.out.println("Caught unchecked exception: " + e.getMessage());
        }

        // ArrayIndexOutOfBoundsException — unchecked
        int[] arr = {1, 2, 3};
        try {
            System.out.println(arr[10]);
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("Array index out of bounds!");
        }
    }
}

import java.util.*;

public class ListDemo {
    public static void main(String[] args) {

        // ArrayList
        List<String> arrayList = new ArrayList<>();
        arrayList.add("Apple");
        arrayList.add("Banana");
        arrayList.add("Cherry");

        System.out.println(arrayList.get(1));  // O(1) fast random access: Banana
        arrayList.add(1, "Avocado");           // O(n) — shifts elements
        System.out.println(arrayList);         // [Apple, Avocado, Banana, Cherry]

        // LinkedList
        LinkedList<String> linkedList = new LinkedList<>();
        linkedList.add("Dog");
        linkedList.add("Cat");
        linkedList.addFirst("Bird");  // O(1) — add to head
        linkedList.addLast("Fish");   // O(1) — add to tail

        System.out.println(linkedList.get(2)); // O(n) — must traverse: Cat
        System.out.println(linkedList);        // [Bird, Dog, Cat, Fish]

        // LinkedList as a Deque (double-ended queue)
        linkedList.pollFirst(); // removes Bird
        linkedList.pollLast();  // removes Fish
        System.out.println(linkedList); // [Dog, Cat]
    }
}

import java.util.*;

public class MapDemo {
    public static void main(String[] args) {

        // HashMap — allows null key and null values
        HashMap<String, String> map = new HashMap<>();
        map.put("name", "Alice");
        map.put("city", null);  // null value allowed
        map.put(null, "unknown"); // null key allowed
        System.out.println(map); // {null=unknown, name=Alice, city=null}

        // Hashtable — does NOT allow null
        Hashtable<String, String> table = new Hashtable<>();
        table.put("name", "Bob");
        // table.put(null, "value"); // throws NullPointerException
        // table.put("key", null);   // throws NullPointerException
        System.out.println(table); // {name=Bob}

        // For thread-safe use, prefer ConcurrentHashMap
        Map<String, Integer> concMap = new java.util.concurrent.ConcurrentHashMap<>();
        concMap.put("score", 100);
        System.out.println(concMap);
    }
}

