// Correct custom key — must override both methods
class Student {
    String name;
    int id;

    Student(String name, int id) {
        this.name = name;
        this.id = id;
    }

    @Override
    public int hashCode() {
        return 31 * name.hashCode() + id;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Student)) return false;
        Student s = (Student) o;
        return id == s.id && name.equals(s.name);
    }
}

import java.util.*;

public class SetDemo {
    public static void main(String[] args) {

        // HashSet — no ordering
        Set<String> hashSet = new HashSet<>();
        hashSet.add("Banana");
        hashSet.add("Apple");
        hashSet.add("Cherry");
        hashSet.add("Apple"); // duplicate — ignored
        System.out.println("HashSet: " + hashSet); // unpredictable order

        // TreeSet — natural sorted order
        Set<String> treeSet = new TreeSet<>(hashSet);
        System.out.println("TreeSet: " + treeSet); // [Apple, Banana, Cherry]

        // LinkedHashSet — insertion order
        Set<String> linkedHashSet = new LinkedHashSet<>();
        linkedHashSet.add("Banana");
        linkedHashSet.add("Apple");
        linkedHashSet.add("Cherry");
        System.out.println("LinkedHashSet: " + linkedHashSet); // [Banana, Apple, Cherry]

        // TreeSet with custom sort
        TreeSet<Integer> numbers = new TreeSet<>(Comparator.reverseOrder());
        numbers.addAll(Arrays.asList(5, 3, 8, 1, 9));
        System.out.println("Reverse TreeSet: " + numbers); // [9, 8, 5, 3, 1]
    }
}

// This example shows observable JVM behaviors
public class JVMDemo {

    // Static field stored in Method Area
    static int staticCount = 0;

    // Instance field stored in Heap
    int instanceCount;

    public JVMDemo(int count) {
        this.instanceCount = count;
    }

    public static void main(String[] args) {
        // Objects go to Heap
        JVMDemo obj1 = new JVMDemo(10);
        JVMDemo obj2 = new JVMDemo(20);

        // Method call frames go on the Stack
        staticCount = add(5, 3);
        System.out.println("Static count: " + staticCount);

        // Checking JVM memory info
        Runtime runtime = Runtime.getRuntime();
        System.out.println("Total memory: " + runtime.totalMemory() / 1024 + " KB");
        System.out.println("Free memory: " + runtime.freeMemory() / 1024 + " KB");
        System.out.println("Max memory: " + runtime.maxMemory() / 1024 + " KB");
    }

    static int add(int a, int b) {
        return a + b; // local variables a, b stored on Stack frame
    }
}

public class GCDemo {
    public static void main(String[] args) throws InterruptedException {

        // These objects become eligible for GC after loop
        for (int i = 0; i < 100000; i++) {
            String temp = new String("Object " + i);
            // 'temp' goes out of scope next iteration — eligible for GC
        }

        System.out.println("Objects created and eligible for GC");

        // Suggest GC (no guarantee it runs)
        System.gc();

        // Check memory after suggestion
        Runtime rt = Runtime.getRuntime();
        System.out.println("Free memory: " + rt.freeMemory() / 1024 + " KB");

        // Demonstrating reachability
        Object obj = new Object(); // reachable — not collected
        obj = null;                // now unreachable — eligible for GC

        // WeakReference example — GC can collect even if referenced
        java.lang.ref.WeakReference<String> weak =
            new java.lang.ref.WeakReference<>(new String("weak data"));
        System.gc();
        System.out.println("WeakReference value: " + weak.get()); // may be null
    }
}

public class ThreadLifecycle {
    public static void main(String[] args) throws InterruptedException {

        Thread thread = new Thread(() -> {
            try {
                System.out.println("Thread running");
                Thread.sleep(500); // TIMED_WAITING
                System.out.println("Thread resumed");
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        });

        // State 1: NEW
        System.out.println("State after creation: " + thread.getState()); // NEW

        thread.start();

        // State 2: RUNNABLE (may also be running)
        System.out.println("State after start: " + thread.getState()); // RUNNABLE

        Thread.sleep(100); // main thread waits briefly

        // State 3: TIMED_WAITING (thread is sleeping)
        System.out.println("State during sleep: " + thread.getState()); // TIMED_WAITING

        thread.join(); // main thread waits for thread to finish

        // State 4: TERMINATED
        System.out.println("State after completion: " + thread.getState()); // TERMINATED
    }
}

public class VolatileDemo {

    // Without volatile, the reading thread might never see the change
    private static volatile boolean running = true;

    public static void main(String[] args) throws InterruptedException {

        Thread worker = new Thread(() -> {
            System.out.println("Worker started");
            while (running) { // reads volatile variable from main memory
                // do work...
            }
            System.out.println("Worker stopped");
        });

        worker.start();
        Thread.sleep(100);
        running = false; // visible to all threads immediately
        System.out.println("Main: set running to false");

        worker.join();
        System.out.println("Done");
    }
}

// volatile does NOT guarantee atomicity!
class VolatileCounterBug {
    private volatile int count = 0;

    public void increment() {
        count++; // NOT atomic! read-modify-write is 3 steps — race condition!
    }

    // Fix: use AtomicInteger
    private java.util.concurrent.atomic.AtomicInteger atomicCount
        = new java.util.concurrent.atomic.AtomicInteger(0);

    public void safeIncrement() {
        atomicCount.incrementAndGet(); // truly atomic
    }
}

public class DeadlockDemo {
    private static final Object lockA = new Object();
    private static final Object lockB = new Object();

    public static void main(String[] args) {
        // Thread 1: acquires lockA, then tries lockB
        Thread t1 = new Thread(() -> {
            synchronized (lockA) {
                System.out.println("T1: holding lockA, waiting for lockB");
                try { Thread.sleep(50); } catch (InterruptedException e) {}
                synchronized (lockB) {
                    System.out.println("T1: acquired both locks");
                }
            }
        });

        // Thread 2: acquires lockB, then tries lockA — DEADLOCK!
        Thread t2 = new Thread(() -> {
            synchronized (lockB) {
                System.out.println("T2: holding lockB, waiting for lockA");
                synchronized (lockA) {
                    System.out.println("T2: acquired both locks");
                }
            }
        });

        t1.start();
        t2.start();
    }
}

// Fix: always acquire locks in the same order
class DeadlockFixed {
    private static final Object lockA = new Object();
    private static final Object lockB = new Object();

    static void thread1() {
        synchronized (lockA) {    // always lockA first
            synchronized (lockB) {
                System.out.println("Thread1 done");
            }
        }
    }

    static void thread2() {
        synchronized (lockA) {    // always lockA first — consistent order
            synchronized (lockB) {
                System.out.println("Thread2 done");
            }
        }
    }
}

import java.util.*;
import java.util.stream.*;

public class MapVsFlatMap {
    public static void main(String[] args) {

        // map() — one-to-one transformation
        List<String> words = Arrays.asList("hello", "world", "java");

        List<String> uppercased = words.stream()
            .map(String::toUpperCase)  // each word → one uppercase word
            .collect(Collectors.toList());
        System.out.println(uppercased); // [HELLO, WORLD, JAVA]

        // map() returns Stream<String[]> — nested structure
        List<String[]> nested = words.stream()
            .map(w -> w.split(""))     // each word → array of chars
            .collect(Collectors.toList());
        System.out.println(nested.size() + " arrays"); // 3 arrays — not flat!

        // flatMap() — one-to-many then flatten
        List<String> letters = words.stream()
            .flatMap(w -> Arrays.stream(w.split(""))) // each word → stream of chars
            .distinct()
            .collect(Collectors.toList());
        System.out.println(letters); // [h, e, l, o, w, r, d, j, a, v]

        // flatMap() to flatten a list of lists
        List<List<Integer>> listOfLists = Arrays.asList(
            Arrays.asList(1, 2, 3),
            Arrays.asList(4, 5),
            Arrays.asList(6, 7, 8, 9)
        );

        List<Integer> flat = listOfLists.stream()
            .flatMap(Collection::stream) // each inner list → stream of integers
            .collect(Collectors.toList());
        System.out.println(flat); // [1, 2, 3, 4, 5, 6, 7, 8, 9]
    }
}

import java.util.*;
import java.util.stream.*;

public class CollectorsDemo {
    record Employee(String name, String dept, double salary) {}

    public static void main(String[] args) {
        List<Employee> employees = List.of(
            new Employee("Alice", "Engineering", 90000),
            new Employee("Bob", "Engineering", 85000),
            new Employee("Charlie", "HR", 70000),
            new Employee("Diana", "HR", 72000),
            new Employee("Eve", "Marketing", 65000)
        );

        // toList
        List<String> names = employees.stream()
            .map(Employee::name)
            .collect(Collectors.toList());
        System.out.println(names);

        // joining
        String joined = employees.stream()
            .map(Employee::name)
            .collect(Collectors.joining(", ", "[", "]"));
        System.out.println(joined); // [Alice, Bob, Charlie, Diana, Eve]

        // groupingBy
        Map<String, List<Employee>> byDept = employees.stream()
            .collect(Collectors.groupingBy(Employee::dept));
        byDept.forEach((dept, emps) -> System.out.println(dept + ": " + emps.size()));

        // counting per group
        Map<String, Long> countByDept = employees.stream()
            .collect(Collectors.groupingBy(Employee::dept, Collectors.counting()));
        System.out.println(countByDept); // {Engineering=2, HR=2, Marketing=1}

        // averagingDouble
        double avgSalary = employees.stream()
            .collect(Collectors.averagingDouble(Employee::salary));
        System.out.println("Avg salary: " + avgSalary);

        // partitioningBy
        Map<Boolean, List<Employee>> partitioned = employees.stream()
            .collect(Collectors.partitioningBy(e -> e.salary() > 75000));
        System.out.println("High earners: " + partitioned.get(true).size());
    }
}

public class BankAccount {

    // Private fields — hidden from outside
    private String owner;
    private double balance;

    public BankAccount(String owner, double initialBalance) {
        this.owner = owner;
        if (initialBalance < 0) {
            throw new IllegalArgumentException("Balance cannot be negative");
        }
        this.balance = initialBalance;
    }

    // Getter — controlled read access
    public double getBalance() {
        return balance;
    }

    public String getOwner() {
        return owner;
    }

    // No setter for owner — owner is immutable after creation

    // Setter with validation
    public void deposit(double amount) {
        if (amount <= 0) {
            throw new IllegalArgumentException("Deposit must be positive");
        }
        balance += amount;
    }

    public void withdraw(double amount) {
        if (amount <= 0 || amount > balance) {
            throw new IllegalArgumentException("Invalid withdrawal amount");
        }
        balance -= amount;
    }
}

public class Main {
    public static void main(String[] args) {
        BankAccount account = new BankAccount("Alice", 1000.0);
        account.deposit(500);
        account.withdraw(200);
        System.out.println("Balance: " + account.getBalance()); // 1300.0
        // account.balance = -500; // COMPILE ERROR — field is private
    }
}

// Runtime Polymorphism
class Shape {
    public double area() {
        return 0;
    }
    public void display() {
        System.out.println("Area: " + area());
    }
}

class Circle extends Shape {
    double radius;
    Circle(double r) { this.radius = r; }

    @Override
    public double area() {
        return Math.PI * radius * radius; // overridden
    }
}

class Rectangle extends Shape {
    double width, height;
    Rectangle(double w, double h) { width = w; height = h; }

    @Override
    public double area() {
        return width * height; // overridden
    }
}

public class PolyDemo {
    public static void main(String[] args) {
        // Parent reference, child objects — runtime polymorphism
        Shape[] shapes = { new Circle(5), new Rectangle(4, 6) };

        for (Shape s : shapes) {
            s.display(); // JVM decides which area() to call at runtime
        }
        // Output:
        // Area: 78.53981...
        // Area: 24.0
    }
}

// Compile-time Polymorphism — method overloading
class Printer {
