    public void print(int n)    { System.out.println("Int: " + n); }
    public void print(double d) { System.out.println("Double: " + d); }
}

import java.util.function.*;
import java.util.*;
import java.util.stream.*;

@FunctionalInterface
interface Greeter {
    String greet(String name);
    // Can only have ONE abstract method
}

public class LambdaDemo {
    public static void main(String[] args) {

        // Lambda implementing custom functional interface
        Greeter g = name -> "Hello, " + name + "!";
        System.out.println(g.greet("Alice")); // Hello, Alice!

        // Predicate<T> — takes T, returns boolean
        Predicate<String> isLong = s -> s.length() > 5;
        System.out.println(isLong.test("Java")); // false
        System.out.println(isLong.test("Programming")); // true

        // Function<T, R> — takes T, returns R
        Function<String, Integer> strLen = String::length;
        System.out.println(strLen.apply("Hello")); // 5

        // Consumer<T> — takes T, no return
        Consumer<String> printer = System.out::println;
        printer.accept("Consuming this string");

        // Supplier<T> — no args, returns T
        Supplier<List<String>> listFactory = ArrayList::new;
        List<String> newList = listFactory.get();
        newList.add("item");

        // BiFunction<T, U, R>
        BiFunction<Integer, Integer, Integer> add = (a, b) -> a + b;
        System.out.println(add.apply(3, 7)); // 10

        // Used in Streams
        List<String> names = List.of("Alice", "Bob", "Charlie", "Dan");
        names.stream()
            .filter(isLong)          // Predicate
            .map(String::toUpperCase) // Function via method reference
            .forEach(printer);        // Consumer
    }
}

import java.util.*;

public class OptionalDemo {

    // Returns Optional instead of null — forces caller to handle absence
    public static Optional<String> findUser(int id) {
        if (id == 1) return Optional.of("Alice");
        return Optional.empty();
    }

    public static void main(String[] args) {

        // Basic usage
        Optional<String> user = findUser(1);
        System.out.println(user.isPresent()); // true
        System.out.println(user.get());       // Alice

        Optional<String> noUser = findUser(99);
        System.out.println(noUser.isEmpty()); // true

        // orElse — provide default
        String name = noUser.orElse("Unknown");
        System.out.println(name); // Unknown

        // orElseGet — lazy default (only computed if empty)
        String name2 = noUser.orElseGet(() -> "Generated Default");
        System.out.println(name2);

        // orElseThrow
        try {
            String name3 = noUser.orElseThrow(() -> new RuntimeException("User not found"));
        } catch (RuntimeException e) {
            System.out.println(e.getMessage()); // User not found
        }

        // ifPresent
        user.ifPresent(u -> System.out.println("Found: " + u)); // Found: Alice

        // map — transform value if present
        Optional<Integer> nameLength = user.map(String::length);
        System.out.println(nameLength.orElse(0)); // 5

        // filter
        Optional<String> longName = user.filter(u -> u.length() > 3);
        System.out.println(longName.isPresent()); // true
    }
}

public class JMMDemo {

    // Without happens-before, this could be broken
    private int value = 0;
    private volatile boolean ready = false;

    // Writer thread
    public void writer() {
        value = 42;      // Write 1
        ready = true;   // Write 2 — volatile write: happens-before any read of 'ready'
    }

    // Reader thread
    public void reader() {
        if (ready) {    // Volatile read — happens-after the volatile write
            // Guaranteed to see value = 42 due to happens-before chain:
            // Write(value=42) HB Write(ready=true) HB Read(ready) HB Read(value)
            System.out.println("Value: " + value); // Always 42
        }
    }

    public static void main(String[] args) throws InterruptedException {
        JMMDemo demo = new JMMDemo();

        Thread writer = new Thread(demo::writer);
        Thread reader = new Thread(demo::reader);

        writer.start();
        writer.join(); // join() creates a happens-before: all writer actions HB join() return

        // Now all writes in writer thread are visible to main/reader
        reader.start();
        reader.join();
    }
}

import java.io.*;

public class TryWithResourcesDemo {

    // Old way — verbose and error-prone
    public static void oldWay(String path) {
        BufferedReader br = null;
        try {
            br = new BufferedReader(new FileReader(path));
            System.out.println(br.readLine());
        } catch (IOException e) {
            e.printStackTrace();
        } finally {
            if (br != null) {
                try {
                    br.close(); // must manually close — easy to forget!
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
        }
    }

    // New way — clean and automatic
    public static void newWay(String path) {
        try (BufferedReader br = new BufferedReader(new FileReader(path))) {
            System.out.println(br.readLine());
        } catch (IOException e) {
            e.printStackTrace();
        }
        // br.close() called automatically!
    }

    // Multiple resources — closed in reverse order
    public static void multipleResources(String src, String dst) throws IOException {
        try (
            BufferedReader reader = new BufferedReader(new FileReader(src));
            BufferedWriter writer = new BufferedWriter(new FileWriter(dst))
        ) {
            String line;
            while ((line = reader.readLine()) != null) {
                writer.write(line);
                writer.newLine();
            }
        } // writer closed first, then reader — automatic
    }

    public static void main(String[] args) {
        newWay("example.txt");
    }
}

// Approach 1: Synchronized method — thread-safe but slow
class SingletonSync {
    private static SingletonSync instance;
    private SingletonSync() {}
    public static synchronized SingletonSync getInstance() {
        if (instance == null) instance = new SingletonSync();
        return instance;
    }
}

// Approach 2: Double-Checked Locking — fast and thread-safe
class SingletonDCL {
    private static volatile SingletonDCL instance; // volatile is essential!
    private SingletonDCL() {}
    public static SingletonDCL getInstance() {
        if (instance == null) {                   // first check (no lock)
            synchronized (SingletonDCL.class) {
                if (instance == null) {           // second check (with lock)
                    instance = new SingletonDCL();
                }
            }
        }
        return instance;
    }
}

// Approach 3: Bill Pugh — RECOMMENDED
class SingletonBillPugh {
    private SingletonBillPugh() {}

    private static class Holder {
        // Loaded only when getInstance() is called — JVM guarantees thread safety
        private static final SingletonBillPugh INSTANCE = new SingletonBillPugh();
    }

    public static SingletonBillPugh getInstance() {
        return Holder.INSTANCE;
    }
}

// Approach 4: Enum — safest, handles serialization
enum SingletonEnum {
    INSTANCE;
    public void doWork() {
        System.out.println("Singleton enum working");
    }
}

public class SingletonDemo {
