        SingletonBillPugh s1 = SingletonBillPugh.getInstance();
        SingletonBillPugh s2 = SingletonBillPugh.getInstance();
        System.out.println(s1 == s2); // true — same instance

        SingletonEnum.INSTANCE.doWork();
    }
}

import java.util.*;
import java.util.concurrent.*;

public class ConcurrentMapDemo {
    public static void main(String[] args) throws InterruptedException {

        // synchronizedMap — entire map is locked per operation
        Map<String, Integer> syncMap = Collections.synchronizedMap(new HashMap<>());

        // ConcurrentHashMap — fine-grained locking, better throughput
        ConcurrentHashMap<String, Integer> concMap = new ConcurrentHashMap<>();

        Runnable writer = () -> {
            for (int i = 0; i < 1000; i++) {
                concMap.put(Thread.currentThread().getName() + i, i);
            }
        };

        Thread t1 = new Thread(writer, "T1");
        Thread t2 = new Thread(writer, "T2");
        t1.start(); t2.start();
        t1.join(); t2.join();
        System.out.println("ConcurrentHashMap size: " + concMap.size()); // 2000

        // Atomic operations on ConcurrentHashMap
        concMap.putIfAbsent("score", 0);
        concMap.computeIfAbsent("newKey", k -> k.length());
        concMap.merge("score", 10, Integer::sum); // atomically update

        // Iteration — ConcurrentHashMap is weakly consistent
        // synchronizedMap needs: synchronized(syncMap) { for(entry : syncMap.entrySet()) {...} }
        concMap.forEach((k, v) -> {}); // safe without external synchronization
    }
}

import java.util.*;
import java.util.stream.*;

public class ParallelStreamDemo {
    public static void main(String[] args) {

        List<Integer> numbers = IntStream.rangeClosed(1, 10_000_000)
            .boxed()
            .collect(Collectors.toList());

        // Sequential stream
        long startSeq = System.currentTimeMillis();
        long sumSeq = numbers.stream()
            .mapToLong(Integer::longValue)
            .sum();
        System.out.println("Sequential sum: " + sumSeq +
            " in " + (System.currentTimeMillis() - startSeq) + "ms");

        // Parallel stream — same result, potentially faster
        long startPar = System.currentTimeMillis();
        long sumPar = numbers.parallelStream()
            .mapToLong(Integer::longValue)
            .sum();
        System.out.println("Parallel sum: " + sumPar +
            " in " + (System.currentTimeMillis() - startPar) + "ms");

        // BAD — shared mutable state in parallel stream causes race condition
        List<Integer> unsafeList = new ArrayList<>();
        numbers.parallelStream().forEach(unsafeList::add); // NOT thread-safe!
        System.out.println("Unsafe list size (may vary!): " + unsafeList.size());

        // GOOD — collect to thread-safe result
        List<Integer> safeList = numbers.parallelStream()
            .filter(n -> n % 2 == 0)
            .collect(Collectors.toList()); // Collectors handle thread safety
        System.out.println("Safe even count: " + safeList.size());

        // unordered() improves parallel performance when order doesn't matter
        long count = numbers.parallelStream()
            .unordered()
            .filter(n -> n % 3 == 0)
            .count();
        System.out.println("Divisible by 3: " + count);
    }
}

