import java.util.*;

public class AutoboxingDemo {
    public static void main(String[] args) {

        // Autoboxing — int automatically becomes Integer
        int primitive = 42;
        Integer boxed = primitive; // autoboxing
        System.out.println(boxed); // 42

        // Unboxing — Integer automatically becomes int
        Integer obj = Integer.valueOf(100);
        int unboxed = obj; // unboxing
        System.out.println(unboxed + 5); // 105

        // Used transparently in Collections
        List<Integer> list = new ArrayList<>();
        list.add(10); // autoboxing: int 10 → Integer(10)
        list.add(20);
        int sum = list.get(0) + list.get(1); // unboxing during addition
        System.out.println(sum); // 30

        // Pitfall 1: NullPointerException on unboxing null
        Integer nullInt = null;
        try {
            int val = nullInt; // NullPointerException!
        } catch (NullPointerException e) {
            System.out.println("NPE from unboxing null!");
        }

        // Pitfall 2: Integer cache — cached range is -128 to 127
        Integer a = 100;
        Integer b = 100;
        System.out.println(a == b);      // true (cached)

        Integer c = 200;
        Integer d = 200;
        System.out.println(c == d);      // false (outside cache range!)
        System.out.println(c.equals(d)); // true — always use equals()
    }
}

import java.util.*;

public class StackQueueDemo {
    public static void main(String[] args) {

        // Stack using Deque (preferred over legacy Stack class)
        Deque<String> stack = new ArrayDeque<>();
        stack.push("First");   // adds to top
        stack.push("Second");
        stack.push("Third");
        System.out.println("Stack top: " + stack.peek()); // Third (look without removing)
        System.out.println("Popped: " + stack.pop());     // Third (removes from top)
        System.out.println("Stack: " + stack);            // [Second, First]

        // Queue using LinkedList
        Queue<String> queue = new LinkedList<>();
        queue.offer("Alice");  // enqueue (add to back)
        queue.offer("Bob");
        queue.offer("Charlie");
        System.out.println("Queue front: " + queue.peek()); // Alice (look without removing)
        System.out.println("Polled: " + queue.poll());      // Alice (remove from front)
        System.out.println("Queue: " + queue);              // [Bob, Charlie]

        // PriorityQueue — natural order, not insertion order
        Queue<Integer> pq = new PriorityQueue<>();
        pq.offer(5);
        pq.offer(1);
        pq.offer(3);
        while (!pq.isEmpty()) {
            System.out.print(pq.poll() + " "); // 1 3 5 — sorted!
        }
    }
}

import java.io.*;

public class ThrowVsThrows {

    // 'throws' declares this method may throw IOException
    // Caller MUST handle or re-declare it
    public static void readFile(String path) throws IOException {
        if (path == null) {
            throw new IllegalArgumentException("Path cannot be null"); // throw — unchecked, no need to declare
        }
        FileReader fr = new FileReader(path);
        // If file not found, FileReader throws FileNotFoundException (a checked IOException)
        fr.close();
    }

    // Can declare multiple exceptions
    public static void processData(String data) throws IOException, IllegalAccessException {
        if (data == null) {
            throw new IllegalAccessException("No data provided"); // explicitly throw checked exception
        }
        System.out.println("Processing: " + data);
    }

    public static void main(String[] args) {
        // Must handle the checked exception declared with 'throws'
        try {
            readFile("data.txt");
        } catch (IOException e) {
            System.out.println("Caught: " + e.getMessage());
        }

        // throw with unchecked exception — no need to catch
        try {
            readFile(null);
        } catch (IllegalArgumentException e) {
            System.out.println("Caught unchecked: " + e.getMessage());
        } catch (IOException e) {
            System.out.println("IO error");
        }
    }
}

