// Comparable — defines natural ordering (by salary)
class Employee implements Comparable<Employee> {
    String name;
    int age;
    double salary;

    Employee(String name, int age, double salary) {
        this.name = name;
        this.age = age;
        this.salary = salary;
    }

    @Override
    public int compareTo(Employee other) {
        return Double.compare(this.salary, other.salary); // natural order: by salary
    }

    @Override
    public String toString() {
        return name + "($" + salary + ")";
    }
}

public class ComparableDemo {
    public static void main(String[] args) {
        List<Employee> employees = new ArrayList<>();
        employees.add(new Employee("Alice", 30, 90000));
        employees.add(new Employee("Bob", 25, 70000));
        employees.add(new Employee("Charlie", 35, 80000));

        // Natural order (Comparable)
        Collections.sort(employees);
        System.out.println("By salary: " + employees);
        // [Bob($70000.0), Charlie($80000.0), Alice($90000.0)]

        // Custom order with Comparator — by name
        employees.sort(Comparator.comparing(e -> e.name));
        System.out.println("By name: " + employees);
        // [Alice, Bob, Charlie]

        // Comparator chaining — by age, then by name
        employees.sort(Comparator.comparingInt((Employee e) -> e.age)
                                 .thenComparing(e -> e.name));
        System.out.println("By age then name: " + employees);

        // Reverse order Comparator
        employees.sort(Comparator.comparingDouble((Employee e) -> e.salary).reversed());
        System.out.println("By salary desc: " + employees);
    }
}

import java.lang.reflect.*;

class Secret {
    private String password = "1234";
    private int code = 42;

    private String decrypt(String input) {
        return "Decrypted: " + input;
    }
}

public class ReflectionDemo {
    public static void main(String[] args) throws Exception {

        // Get Class object
        Class<?> clazz = Class.forName("Secret");
        System.out.println("Class: " + clazz.getName());

        // Inspect declared fields (including private)
        Field[] fields = clazz.getDeclaredFields();
        for (Field f : fields) {
            System.out.println("Field: " + f.getName() + " (" + f.getType().getSimpleName() + ")");
        }

        // Create instance dynamically
        Object secretObj = clazz.getDeclaredConstructor().newInstance();

        // Access private field
        Field passwordField = clazz.getDeclaredField("password");
        passwordField.setAccessible(true); // bypass access control
        System.out.println("Password: " + passwordField.get(secretObj)); // 1234

        // Modify private field
        passwordField.set(secretObj, "hacked!");
        System.out.println("Modified: " + passwordField.get(secretObj)); // hacked!

        // Invoke private method
        Method decrypt = clazz.getDeclaredMethod("decrypt", String.class);
        decrypt.setAccessible(true);
        String result = (String) decrypt.invoke(secretObj, "hello");
        System.out.println(result); // Decrypted: hello

        // List all methods
        for (Method m : clazz.getDeclaredMethods()) {
            System.out.println("Method: " + m.getName());
        }
    }
}

import java.util.concurrent.*;
import java.util.*;

public class ExecutorDemo {
    public static void main(String[] args) throws InterruptedException, ExecutionException {

        // Fixed thread pool — 3 threads handle all tasks
        ExecutorService executor = Executors.newFixedThreadPool(3);

        // Submit Runnable (no return value)
        for (int i = 1; i <= 5; i++) {
            final int taskId = i;
            executor.submit(() -> {
                System.out.println("Task " + taskId + " by " + Thread.currentThread().getName());
                try { Thread.sleep(100); } catch (InterruptedException e) {}
            });
        }

        // Submit Callable (returns a value via Future)
        Future<Integer> future = executor.submit(() -> {
            Thread.sleep(200);
            return 42; // result of computation
        });

        System.out.println("Result: " + future.get()); // blocks until result is ready

        // Submit multiple Callables and get all results
        List<Callable<String>> tasks = new ArrayList<>();
        for (int i = 1; i <= 3; i++) {
            final int id = i;
            tasks.add(() -> "Result-" + id);
        }
        List<Future<String>> futures = executor.invokeAll(tasks);
        for (Future<String> f : futures) {
            System.out.println(f.get());
        }

        // Always shut down to release resources
        executor.shutdown();
        executor.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("All tasks done");
    }
}

import java.util.*;
import java.util.stream.*;

public class ReduceDemo {
    public static void main(String[] args) {

        List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);

        // reduce(identity, BinaryOperator) — always returns T
        int sum = numbers.stream()
            .reduce(0, Integer::sum); // 0+1+2+3+4+5
        System.out.println("Sum: " + sum); // 15

        int product = numbers.stream()
            .reduce(1, (a, b) -> a * b); // 1*1*2*3*4*5
        System.out.println("Product: " + product); // 120

        // reduce(BinaryOperator) — returns Optional (stream might be empty)
        Optional<Integer> max = numbers.stream()
            .reduce(Integer::max);
        max.ifPresent(m -> System.out.println("Max: " + m)); // 5

        // Concatenation
        Optional<String> concat = Stream.of("Java", " ", "Streams", " ", "Rock")
            .reduce((a, b) -> a + b);
        System.out.println(concat.orElse("empty")); // Java Streams Rock

        // Custom object reduction
        List<String> words = Arrays.asList("the", "quick", "brown", "fox");
        String longest = words.stream()
            .reduce("", (a, b) -> a.length() >= b.length() ? a : b);
        System.out.println("Longest: " + longest); // quick

        // Empty stream with identity
        int sumEmpty = Stream.<Integer>empty()
            .reduce(0, Integer::sum);
        System.out.println("Empty sum: " + sumEmpty); // 0 (identity returned)

        // Without identity on empty stream
        Optional<Integer> emptyOpt = Stream.<Integer>empty()
            .reduce(Integer::sum);
        System.out.println("Empty optional: " + emptyOpt.isPresent()); // false
    }
}

// Factory Pattern
interface Shape {
    void draw();
}

class Circle implements Shape {
    public void draw() { System.out.println("Drawing Circle"); }
}

class Rectangle implements Shape {
    public void draw() { System.out.println("Drawing Rectangle"); }
}

class ShapeFactory {
    // Factory method — client doesn't know which class is instantiated
    public static Shape create(String type) {
        return switch (type.toLowerCase()) {
            case "circle"    -> new Circle();
            case "rectangle" -> new Rectangle();
            default -> throw new IllegalArgumentException("Unknown shape: " + type);
        };
    }
