// Custom Iterable class
class NumberRange implements Iterable<Integer> {
    private final int start;
    private final int end;

    NumberRange(int start, int end) {
        this.start = start;
        this.end = end;
    }

    @Override
    public Iterator<Integer> iterator() {
        return new Iterator<Integer>() {
            int current = start;

            @Override
            public boolean hasNext() {
                return current <= end;
            }

            @Override
            public Integer next() {
                if (!hasNext()) throw new NoSuchElementException();
                return current++;
            }
        };
    }
}

public class IteratorDemo {
    public static void main(String[] args) {

        // Custom Iterable in for-each
        NumberRange range = new NumberRange(1, 5);
        for (int n : range) {
            System.out.print(n + " "); // 1 2 3 4 5
        }
        System.out.println();

        // Explicit Iterator usage — allows removal during iteration
        List<String> fruits = new ArrayList<>(Arrays.asList("Apple", "Banana", "Cherry", "Date"));

        Iterator<String> it = fruits.iterator();
        while (it.hasNext()) {
            String fruit = it.next();
            if (fruit.startsWith("B")) {
                it.remove(); // safe removal during iteration
            }
        }
        System.out.println(fruits); // [Apple, Cherry, Date]

        // WRONG: modifying list directly during for-each throws ConcurrentModificationException
        // for (String f : fruits) { fruits.remove(f); } // DON'T DO THIS

        // Java 8+: removeIf — cleaner alternative
        fruits.removeIf(f -> f.length() > 5);
        System.out.println(fruits); // [Apple, Date] — 'Cherry' removed
    }
}

