// Custom checked exception — caller must handle
class InsufficientFundsException extends Exception {
    private final double amount;
    private final double balance;

    public InsufficientFundsException(double amount, double balance) {
        super(String.format("Cannot withdraw $%.2f: balance is $%.2f", amount, balance));
        this.amount = amount;
        this.balance = balance;
    }

    // Constructor with cause — for exception chaining
    public InsufficientFundsException(String message, Throwable cause) {
        super(message, cause);
        this.amount = 0;
        this.balance = 0;
    }

    public double getAmount() { return amount; }
    public double getBalance() { return balance; }
}

// Custom unchecked exception — programming error
class InvalidAccountStateException extends RuntimeException {
    public InvalidAccountStateException(String accountId, String state) {
        super("Account " + accountId + " is in invalid state: " + state);
    }
}

class BankAccount {
    private String id;
    private double balance;
    private boolean active;

    BankAccount(String id, double balance) {
        this.id = id;
        this.balance = balance;
        this.active = true;
    }

    // Throws checked exception — caller must handle
    public void withdraw(double amount) throws InsufficientFundsException {
        if (!active) throw new InvalidAccountStateException(id, "CLOSED"); // unchecked
        if (amount > balance) throw new InsufficientFundsException(amount, balance);
        balance -= amount;
    }
}

