import java.util.concurrent.*;

public class CompletableFutureDemo {
    public static void main(String[] args) throws Exception {

        // Basic async task
        CompletableFuture<String> future = CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(200); } catch (InterruptedException e) {}
            return "Hello from async thread!";
        });

        // Non-blocking: chain transformations
        CompletableFuture<String> chained = future
            .thenApply(s -> s.toUpperCase())     // transform result
            .thenApply(s -> ">> " + s + " <<");  // another transformation

        System.out.println(chained.get()); // >> HELLO FROM ASYNC THREAD! <<

        // Consume result
        CompletableFuture.supplyAsync(() -> 42)
            .thenAccept(val -> System.out.println("Value: " + val))
            .join(); // wait for completion

        // Combine two independent async tasks
        CompletableFuture<String> name = CompletableFuture.supplyAsync(() -> "Alice");
        CompletableFuture<Integer> score = CompletableFuture.supplyAsync(() -> 95);

        CompletableFuture<String> combined = name.thenCombine(score,
            (n, s) -> n + " scored " + s);
        System.out.println(combined.get()); // Alice scored 95

        // Exception handling
        CompletableFuture<Integer> safeFuture = CompletableFuture
            .supplyAsync(() -> {
                if (true) throw new RuntimeException("Something failed!");
                return 0;
            })
            .exceptionally(ex -> {
                System.out.println("Caught: " + ex.getMessage());
                return -1; // fallback value
            });
        System.out.println("Result: " + safeFuture.get()); // Result: -1

        // Wait for all
        CompletableFuture<Void> allOf = CompletableFuture.allOf(
            CompletableFuture.supplyAsync(() -> "task1"),
            CompletableFuture.supplyAsync(() -> "task2")
        );
        allOf.join();
        System.out.println("All tasks done");
    }
}

// Sealed interface — only these three types permitted
sealed interface Shape permits Circle, Rectangle, Triangle {}

final class Circle implements Shape {
    double radius;
    Circle(double radius) { this.radius = radius; }
}

final class Rectangle implements Shape {
    double width, height;
    Rectangle(double w, double h) { width = w; height = h; }
}

final class Triangle implements Shape {
    double base, height;
    Triangle(double b, double h) { base = b; height = h; }
}

public class SealedDemo {

    // Pattern matching switch — exhaustive over sealed type, no default needed
    static double area(Shape shape) {
        return switch (shape) {
            case Circle c    -> Math.PI * c.radius * c.radius;
            case Rectangle r -> r.width * r.height;
            case Triangle t  -> 0.5 * t.base * t.height;
            // No default needed — compiler knows all cases are covered!
        };
    }

    static String describe(Shape shape) {
        return switch (shape) {
            case Circle c    when c.radius > 10 -> "Large circle";
            case Circle c                       -> "Small circle";
            case Rectangle r when r.width == r.height -> "Square";
            case Rectangle r -> "Rectangle";
            case Triangle t  -> "Triangle";
        };
    }

    // Pattern matching for instanceof (Java 16)
    static void printInfo(Object obj) {
        if (obj instanceof String s) { // type pattern — s is bound directly
            System.out.println("String of length " + s.length());
        } else if (obj instanceof Integer i && i > 0) {
            System.out.println("Positive integer: " + i);
        }
    }

    public static void main(String[] args) {
        Shape[] shapes = {new Circle(5), new Rectangle(4, 6), new Triangle(3, 8)};
        for (Shape s : shapes) {
            System.out.printf("%s: area=%.2f%n", s.getClass().getSimpleName(), area(s));
        }

        printInfo("Hello");
        printInfo(42);
    }
}

