interface Validator<T> {

    // Abstract method — must be implemented
    boolean validate(T value);

    // Default method — provided, can be overridden
    default String validationMessage(T value) {
        return validate(value) ? "Valid: " + value : "Invalid: " + value;
    }

    // Default method combining other defaults
    default boolean validateAndLog(T value) {
        boolean result = validate(value);
        System.out.println(validationMessage(value));
        return result;
    }

    // Static method — belongs to the interface, not instances
    static <T> Validator<T> noOp() {
        return value -> true; // always valid
    }
}

// Implements abstract method; inherits default methods
