public class StreamIntroDemo {
    public static void main(String[] args) {

        List<String> names = Arrays.asList(
            "Alice", "Bob", "Anna", "Charlie", "Adam", "Brian"
        );

        // filter() + map() + collect() pipeline
        List<String> result = names.stream()
            .filter(name -> name.startsWith("A"))    // keep names starting with A
            .map(String::toUpperCase)                // convert to uppercase
            .sorted()                                // sort alphabetically
            .collect(Collectors.toList());           // gather into a List

        System.out.println(result); // [ADAM, ALICE, ANNA]

        // Count matching elements
        long count = names.stream()
            .filter(name -> name.length() > 4)
            .count();
        System.out.println("Names longer than 4 chars: " + count); // 3

        // Find first match
        Optional<String> first = names.stream()
            .filter(name -> name.contains("b") || name.contains("B"))
            .findFirst();
        first.ifPresent(n -> System.out.println("First match: " + n)); // Bob

        // Collect to Set (removes duplicates)
        List<Integer> nums = Arrays.asList(1, 2, 2, 3, 3, 3, 4);
        Set<Integer> unique = nums.stream().collect(Collectors.toSet());
        System.out.println(unique); // [1, 2, 3, 4] (order not guaranteed)

        // forEach — terminal operation, no return value
        names.stream()
            .filter(n -> n.startsWith("B"))
            .forEach(System.out::println); // Bob, Brian
    }
}

public class StringPoolDemo {
    public static void main(String[] args) {

        // String literals — go into the String Pool
        String a = "hello";
        String b = "hello";
        System.out.println(a == b);       // true — same pool object
        System.out.println(a.equals(b)); // true — same content

        // new String() — creates a new heap object, bypasses pool
        String c = new String("hello");
        String d = new String("hello");
        System.out.println(c == d);       // false — different heap objects
        System.out.println(c.equals(d)); // true — same content

        System.out.println(a == c);       // false — pool vs heap object
        System.out.println(a.equals(c)); // true — same content

        // intern() — adds to pool or returns existing pool reference
        String e = c.intern(); // returns the pool reference for "hello"
        System.out.println(a == e); // true — both point to pool object

        // Concatenation with + at compile time — goes into pool
        String x = "hel" + "lo"; // compile-time constant — pooled!
        System.out.println(a == x); // true — compiler computes "hello" at compile time

        // Concatenation at runtime — creates new heap object
        String part = "hel";
        String y = part + "lo"; // runtime concat — NOT pooled
        System.out.println(a == y); // false
        System.out.println(a.equals(y)); // true
    }
}

import java.util.*;

public class DequeDemo {
    public static void main(String[] args) {

        ArrayDeque<String> deque = new ArrayDeque<>();

        // Add to both ends
        deque.addFirst("Middle");
        deque.addFirst("Front");
        deque.addLast("Back");
        System.out.println(deque); // [Front, Middle, Back]

        // Peek both ends (no removal)
        System.out.println("First: " + deque.peekFirst()); // Front
        System.out.println("Last: " + deque.peekLast());   // Back

        // Remove from both ends
        System.out.println("Removed first: " + deque.removeFirst()); // Front
        System.out.println("Removed last: " + deque.removeLast());   // Back
        System.out.println(deque); // [Middle]

        // ===  Use as STACK (LIFO) ===
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(1); // addFirst
        stack.push(2);
        stack.push(3);
        System.out.println("Stack peek: " + stack.peek()); // 3
        System.out.println("Stack pop: " + stack.pop());   // 3
        System.out.println("Stack pop: " + stack.pop());   // 2

        // === Use as QUEUE (FIFO) ===
        Deque<String> queue = new ArrayDeque<>();
        queue.offer("Alice");  // offerLast — adds to back
        queue.offer("Bob");
        queue.offer("Charlie");
        System.out.println("Queue poll: " + queue.poll());  // Alice (from front)
        System.out.println("Queue poll: " + queue.poll());  // Bob
        System.out.println("Remaining: " + queue);          // [Charlie]
    }
}

