import java.io.*;
import java.sql.*;

public class MultiCatchDemo {

    // Method that can throw multiple checked exceptions
    public static void process(String input) throws IOException, SQLException {
        if (input == null) throw new IOException("Input is null");
        if (input.isEmpty()) throw new SQLException("Empty query");
        System.out.println("Processed: " + input);
    }

    public static void main(String[] args) {

        // ===  Without multi-catch (verbose) ===
        try {
            process("data");
        } catch (IOException e) {
            System.out.println("IO error: " + e.getMessage());
        } catch (SQLException e) {
            System.out.println("SQL error: " + e.getMessage());
        }

        // === With multi-catch (Java 7+) — same handling for both ===
        try {
            process(null);
        } catch (IOException | SQLException e) { // multi-catch
            System.out.println("Processing error: " + e.getMessage());
            // 'e' is implicitly final here — cannot reassign
        }

        // Catch order — specific before general
        try {
            int[] arr = new int[3];
            arr[10] = 5; // ArrayIndexOutOfBoundsException
        } catch (ArrayIndexOutOfBoundsException e) { // specific first
            System.out.println("Index error: " + e.getMessage());
        } catch (RuntimeException e) {              // general next
            System.out.println("Runtime error");
        } catch (Exception e) {                     // most general last
            System.out.println("General error");
        }

        // The exception hierarchy in practice
        // FileNotFoundException IS-A IOException — catch FileNotFoundException first if needed
        try {
            new FileReader("missing.txt");
        } catch (FileNotFoundException e) {   // more specific
            System.out.println("File missing: " + e.getMessage());
        }
    }
}

import java.util.*;

public class CollectionsUtilDemo {
    public static void main(String[] args) {

        List<Integer> nums = new ArrayList<>(Arrays.asList(3, 1, 4, 1, 5, 9, 2, 6));

        // sort and reverse
        Collections.sort(nums);
        System.out.println("Sorted: " + nums);    // [1, 1, 2, 3, 4, 5, 6, 9]

        Collections.reverse(nums);
        System.out.println("Reversed: " + nums);  // [9, 6, 5, 4, 3, 2, 1, 1]

        // min and max
        System.out.println("Min: " + Collections.min(nums)); // 1
        System.out.println("Max: " + Collections.max(nums)); // 9

        // frequency
        System.out.println("Frequency of 1: " + Collections.frequency(nums, 1)); // 2

        // shuffle — random order
        Collections.shuffle(nums);
        System.out.println("Shuffled: " + nums); // random

        // swap elements by index
        List<String> words = new ArrayList<>(Arrays.asList("A", "B", "C", "D"));
        Collections.swap(words, 0, 3);
        System.out.println("Swapped: " + words); // [D, B, C, A]

        // fill — replace all with one value
        Collections.fill(words, "X");
        System.out.println("Filled: " + words); // [X, X, X, X]

        // unmodifiable view
        List<String> immutable = Collections.unmodifiableList(Arrays.asList("a", "b", "c"));
        try {
            immutable.add("d"); // throws UnsupportedOperationException
        } catch (UnsupportedOperationException e) {
            System.out.println("Cannot modify unmodifiable list!");
        }

        // nCopies
        List<String> copies = Collections.nCopies(4, "Java");
        System.out.println(copies); // [Java, Java, Java, Java]

        // disjoint
        Set<Integer> s1 = new HashSet<>(Arrays.asList(1, 2, 3));
        Set<Integer> s2 = new HashSet<>(Arrays.asList(4, 5, 6));
        System.out.println("Disjoint: " + Collections.disjoint(s1, s2)); // true
    }
}

public class MemoryDemo {

    // Instance variable — stored on Heap (part of the object)
    int instanceVar = 10;

    static void methodA() {
        // Local primitive — stored on Stack
        int x = 5;
        int y = 10;
        int sum = x + y; // all on stack

        // Reference on Stack, object on Heap
        String str = new String("hello"); // 'str' (reference) on stack, object on heap

        methodB(sum);
    } // x, y, sum, str reference all popped from stack; 'hello' object becomes GC eligible

    static void methodB(int value) {
        // 'value' is a copy pushed onto a new stack frame
        int doubled = value * 2;
        System.out.println(doubled);
    } // value, doubled popped from stack

    public static void main(String[] args) {

        // Object on heap, reference on stack
        MemoryDemo obj = new MemoryDemo(); // obj reference on stack, MemoryDemo object on heap

        // Demonstrating StackOverflowError
        try {
            recursive(0);
        } catch (StackOverflowError e) {
            System.out.println("Stack overflow — too many nested calls!");
        }

        // OutOfMemoryError (heap) — not demonstrated, but would occur with:
        // List<byte[]> leak = new ArrayList<>();
        // while(true) { leak.add(new byte[1024 * 1024]); } // OutOfMemoryError

        methodA();
    }

    static void recursive(int depth) {
        recursive(depth + 1); // infinite recursion → StackOverflowError
    }
}

import java.util.*;

// Immutable class — all rules applied
public final class ImmutableEmployee { // Step 1: final class

    private final String name;     // Step 2: private final fields
    private final int age;
    private final List<String> skills; // mutable field — needs defensive copy!

    // Step 3: constructor initializes all fields
    public ImmutableEmployee(String name, int age, List<String> skills) {
        this.name = name;
        this.age = age;
        // Step 5: defensive copy of mutable input
        this.skills = Collections.unmodifiableList(new ArrayList<>(skills));
    }

    // Step 4: only getters, no setters
    public String getName() { return name; }
    public int getAge()     { return age; }

    // Step 5: return defensive copy of mutable field
    public List<String> getSkills() {
        return skills; // already unmodifiable — safe to return directly
    }

    @Override
    public String toString() {
        return "ImmutableEmployee{name='" + name + "', age=" + age + ", skills=" + skills + "}";
    }
}

class ImmutableDemo {
    public static void main(String[] args) {
        List<String> skills = new ArrayList<>(Arrays.asList("Java", "Python"));
        ImmutableEmployee emp = new ImmutableEmployee("Alice", 30, skills);

        System.out.println(emp);

        // Modifying the original list does NOT affect emp
        skills.add("C++");
        System.out.println(emp.getSkills()); // still [Java, Python] — defensive copy worked!

        // Attempting to modify the returned list
        try {
            emp.getSkills().add("Kotlin"); // UnsupportedOperationException
        } catch (UnsupportedOperationException e) {
            System.out.println("Cannot modify immutable list!");
        }
    }
}

public class WaitNotifyDemo {
    private static final Object lock = new Object();
    private static boolean dataReady = false;
    private static int data = 0;

    public static void main(String[] args) throws InterruptedException {

        // Consumer thread — waits until data is ready
        Thread consumer = new Thread(() -> {
            synchronized (lock) {
                // ALWAYS use while loop, not if — guard against spurious wakeups
                while (!dataReady) {
                    try {
                        System.out.println("Consumer waiting...");
                        lock.wait(); // releases lock and waits
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        return;
                    }
                }
                System.out.println("Consumer received data: " + data);
            }
        });

        // Producer thread — produces data and notifies consumer
        Thread producer = new Thread(() -> {
            try { Thread.sleep(500); } catch (InterruptedException e) {}

            synchronized (lock) {
                data = 42;
                dataReady = true;
                System.out.println("Producer: data ready, notifying...");
                lock.notify(); // wake up ONE waiting thread
                // lock.notifyAll(); // wake up ALL waiting threads
            }
        });

        consumer.start();
        producer.start();

        consumer.join();
        producer.join();
        System.out.println("Done");
    }
}

import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class MethodReferenceDemo {
    public static void main(String[] args) {

        List<String> names = Arrays.asList("alice", "bob", "charlie", "diana");

        // 1. Static method reference — ClassName::staticMethod
        // Lambda:          s -> Integer.parseInt(s)
        // Method ref:      Integer::parseInt
        List<String> numStrings = Arrays.asList("1", "2", "3");
        List<Integer> parsed = numStrings.stream()
            .map(Integer::parseInt) // static method reference
            .collect(Collectors.toList());
        System.out.println(parsed); // [1, 2, 3]

        // 2. Instance method reference of a particular object
        // Lambda:          s -> System.out.println(s)
        // Method ref:      System.out::println
        names.stream()
            .filter(n -> n.length() > 3)
            .forEach(System.out::println); // instance method on specific System.out object

        // 3. Instance method reference of an arbitrary instance (type-specific)
        // Lambda:          s -> s.toUpperCase()
        // Method ref:      String::toUpperCase
        List<String> upper = names.stream()
            .map(String::toUpperCase) // called on each String element
            .collect(Collectors.toList());
        System.out.println(upper); // [ALICE, BOB, CHARLIE, DIANA]

        // Lambda:          (s1, s2) -> s1.compareToIgnoreCase(s2)
        // Method ref:      String::compareToIgnoreCase
        names.sort(String::compareToIgnoreCase);
        System.out.println(names); // [alice, bob, charlie, diana]

        // 4. Constructor reference — ClassName::new
        // Lambda:          () -> new ArrayList<>()
        // Method ref:      ArrayList::new
        Supplier<List<String>> listFactory = ArrayList::new;
        List<String> newList = listFactory.get();
        newList.add("hello");
        System.out.println(newList); // [hello]

        // Constructor ref with argument
        // Lambda:          s -> new StringBuilder(s)
        // Method ref:      StringBuilder::new
        Function<String, StringBuilder> sbFactory = StringBuilder::new;
        System.out.println(sbFactory.apply("Java")); // Java
    }
}

import java.util.*;

public class MemoryLeakExamples {

    // BAD: Static collection that never removes entries — MEMORY LEAK
    private static Map<String, byte[]> cache = new HashMap<>();

    public static void leakWithStaticCache() {
        for (int i = 0; i < 10000; i++) {
            cache.put("key" + i, new byte[1024]); // keeps growing, never freed
        }
        System.out.println("Cache size: " + cache.size()); // 10000 — never shrinks
    }

    // GOOD: Use WeakHashMap so GC can reclaim entries when keys are no longer strongly referenced
    private static WeakHashMap<String, byte[]> weakCache = new WeakHashMap<>();

    // BAD: Not closing resources — POTENTIAL LEAK
    // public void badResourceHandling() {
    //     FileInputStream fis = new FileInputStream("file.txt");
    //     // ... if exception thrown before close(), resource leaks!
    // }

    // GOOD: try-with-resources — always closes
    // public void goodResourceHandling() throws IOException {
    //     try (FileInputStream fis = new FileInputStream("file.txt")) {
    //         // fis auto-closed even if exception
    //     }
    // }

    // BAD: ThreadLocal not cleaned in thread pool
    static ThreadLocal<byte[]> threadLocal = new ThreadLocal<>();

    public static void leakWithThreadLocal() {
        // In a thread pool, thread is reused — value persists after task finishes
        threadLocal.set(new byte[1024 * 1024]); // 1MB per thread
        try {
            // do work
        } finally {
            threadLocal.remove(); // GOOD: always clean up in finally!
        }
    }

    public static void main(String[] args) {
        // Simulate leak
        leakWithStaticCache();

        // Demonstrate fix with WeakHashMap
        String key = new String("weakKey");
        weakCache.put(key, new byte[1024]);
        System.out.println("Weak cache size before GC: " + weakCache.size()); // 1
        key = null; // remove strong reference — now GC can collect the entry
        System.gc();
        System.out.println("Weak cache size after GC: " + weakCache.size()); // 0 (may vary)
    }
}

