import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

public class BlockingQueueDemo {

    private static final BlockingQueue<Integer> queue = new ArrayBlockingQueue<>(5); // capacity 5
    private static final AtomicInteger producedCount = new AtomicInteger(0);

    static class Producer implements Runnable {
        private final int totalItems;

        Producer(int total) { this.totalItems = total; }

        @Override
        public void run() {
            for (int i = 1; i <= totalItems; i++) {
                try {
                    queue.put(i); // BLOCKS if queue is full — waits for consumer
                    System.out.println("Produced: " + i + " | Queue size: " + queue.size());
                    producedCount.incrementAndGet();
                    Thread.sleep(50); // simulate production time
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    return;
                }
            }
            System.out.println("Producer done");
        }
    }

    static class Consumer implements Runnable {
        @Override
        public void run() {
            while (true) {
                try {
                    // poll with timeout instead of blocking forever
                    Integer item = queue.poll(1, TimeUnit.SECONDS);
                    if (item == null) {
                        System.out.println("Consumer: no more items, exiting");
                        return;
                    }
                    System.out.println("Consumed: " + item);
                    Thread.sleep(150); // slower consumer — queue fills up
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    return;
                }
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        ExecutorService executor = Executors.newFixedThreadPool(3);
        executor.submit(new Producer(10));
        executor.submit(new Consumer());
        executor.submit(new Consumer()); // two consumers

        executor.shutdown();
        executor.awaitTermination(10, TimeUnit.SECONDS);
        System.out.println("Total produced: " + producedCount.get());
    }
}

import java.lang.annotation.*;
import java.lang.reflect.*;

// Step 1: Define a custom annotation
@Target({ElementType.METHOD, ElementType.TYPE}) // where it can be used
@Retention(RetentionPolicy.RUNTIME)             // available via reflection at runtime
@Documented                                     // include in Javadoc
public @interface Auditable {
    String action() default "UNKNOWN";          // element with default value
    String category() default "GENERAL";
    boolean required() default true;
}

// Step 2: Apply the annotation
@Auditable(action = "CREATE_USER", category = "USER_MGMT")
class UserService {

    @Auditable(action = "FETCH_USER")
    public String getUser(int id) {
        return "User_" + id;
    }

    @Auditable(action = "DELETE_USER", required = false)
    public void deleteUser(int id) {
        System.out.println("Deleted user: " + id);
    }
}

// Step 3: Process annotation at runtime using Reflection
class AnnotationProcessor {
    public static void process(Class<?> clazz) {
        // Check class-level annotation
        if (clazz.isAnnotationPresent(Auditable.class)) {
            Auditable classAnnotation = clazz.getAnnotation(Auditable.class);
            System.out.println("Class annotated: " + classAnnotation.action()
                + " | category: " + classAnnotation.category());
        }

        // Check method-level annotations
        for (Method method : clazz.getDeclaredMethods()) {
            if (method.isAnnotationPresent(Auditable.class)) {
                Auditable ann = method.getAnnotation(Auditable.class);
                System.out.println("Method: " + method.getName()
                    + " | action: " + ann.action()
                    + " | required: " + ann.required());
            }
        }
    }
}

class AnnotationDemo {
    public static void main(String[] args) {
        AnnotationProcessor.process(UserService.class);
        // Class annotated: CREATE_USER | category: USER_MGMT
        // Method: getUser | action: FETCH_USER | required: true
        // Method: deleteUser | action: DELETE_USER | required: false
    }
}

import java.util.*;
import java.util.stream.*;
import java.util.function.*;

public class CustomCollectorDemo {

    // Custom Collector that collects into an unmodifiable sorted list
    static <T extends Comparable<T>> Collector<T, List<T>, List<T>> toSortedUnmodifiableList() {
        return Collector.of(
            ArrayList::new,                              // 1. supplier: new container
            List::add,                                   // 2. accumulator: add element
            (left, right) -> { left.addAll(right); return left; }, // 3. combiner: merge for parallel
            list -> {                                     // 4. finisher: sort and make unmodifiable
                Collections.sort(list);
                return Collections.unmodifiableList(list);
            }
        );
    }

    // Custom Collector: collect strings into a joined string with count prefix
    static Collector<String, List<String>, String> toCountedJoinedString() {
        return Collector.of(
            ArrayList::new,
            List::add,
            (l1, l2) -> { l1.addAll(l2); return l1; },
            list -> list.size() + " items: [" + String.join(", ", list) + "]",
            Collector.Characteristics.UNORDERED
        );
    }

    public static void main(String[] args) {
        List<Integer> numbers = Arrays.asList(5, 3, 1, 4, 1, 5, 9, 2, 6);

        // Use custom sorted unmodifiable collector
        List<Integer> sortedResult = numbers.stream()
            .collect(toSortedUnmodifiableList());
        System.out.println("Sorted unmodifiable: " + sortedResult);
        // [1, 1, 2, 3, 4, 5, 5, 6, 9]

        try {
            sortedResult.add(10); // UnsupportedOperationException
        } catch (UnsupportedOperationException e) {
            System.out.println("Cannot modify — collector made it unmodifiable!");
        }

        // Use custom counted-joined-string collector
        List<String> fruits = Arrays.asList("Apple", "Banana", "Cherry");
        String counted = fruits.stream().collect(toCountedJoinedString());
        System.out.println(counted); // 3 items: [Apple, Banana, Cherry]

        // Built-in Collectors for comparison
        String builtIn = fruits.stream().collect(Collectors.joining(", ", "[", "]"));
        System.out.println(builtIn); // [Apple, Banana, Cherry]
    }
}

import java.util.concurrent.*;
import java.time.*;

public class VirtualThreadDemo {
    public static void main(String[] args) throws InterruptedException, ExecutionException {

        // Creating a single virtual thread
        Thread vt = Thread.ofVirtual().start(() -> {
            System.out.println("Virtual thread: " + Thread.currentThread());
            System.out.println("Is virtual: " + Thread.currentThread().isVirtual());
        });
        vt.join();

        // Virtual thread per task executor — key use case
        // Creates a new virtual thread for EVERY submitted task
        ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();

        // Simulate 10,000 concurrent tasks (impossible with platform threads)
        int taskCount = 10_000;
        var latch = new java.util.concurrent.CountDownLatch(taskCount);

        Instant start = Instant.now();
        for (int i = 0; i < taskCount; i++) {
            executor.submit(() -> {
                try {
                    Thread.sleep(100); // simulate I/O wait
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    latch.countDown();
                }
            });
        }
        latch.await();
        Duration elapsed = Duration.between(start, Instant.now());
        System.out.println(taskCount + " tasks in " + elapsed.toMillis() + "ms");
        // ~100ms — all run concurrently!
        // With platform thread pool of 200 threads: ~5000ms (50 batches * 100ms each)

        executor.shutdown();

        // Best practice: prefer ReentrantLock over synchronized in virtual thread code
        // synchronized may 'pin' the virtual thread to the carrier thread
        // (ReentrantLock + virtual threads = no pinning)

        // Check if current thread is virtual
        System.out.println("Main is virtual: " + Thread.currentThread().isVirtual()); // false
    }
}

import java.util.Arrays;
import java.util.List;

public class VarargsDemo {

    // Basic varargs method
    static int sum(int... numbers) {
        int total = 0;
        for (int n : numbers) {
            total += n;
        }
        return total;
    }

    // Varargs combined with a regular parameter (varargs must be last)
    static void printAll(String prefix, String... items) {
        for (String item : items) {
            System.out.println(prefix + item);
        }
    }

    // Generic varargs - can cause heap pollution warnings
    @SafeVarargs
    static <T> List<T> listOf(T... elements) {
        return Arrays.asList(elements);
    }

    public static void main(String[] args) {
        System.out.println(sum());           // 0 - empty array, not null
        System.out.println(sum(1, 2, 3));     // 6
        System.out.println(sum(new int[]{4, 5, 6})); // 15 - passing an array directly works too

        printAll("> ", "Apple", "Banana", "Cherry");

        List<String> fruits = listOf("Mango", "Kiwi");
        System.out.println(fruits);

        // Overload resolution: exact match wins over varargs
        show("hello");        // calls show(String) if it exists, not show(String...)
    }

    static void show(String s) {
        System.out.println("Exact match: " + s);
    }

    static void show(String... s) {
        System.out.println("Varargs match");
    }
}

import java.util.HashSet;
import java.util.Objects;
import java.util.Set;

public class HashCodeEqualsDemo {

    static class BrokenPerson {
        String name;
        BrokenPerson(String name) { this.name = name; }

        @Override
        public boolean equals(Object o) {
            if (!(o instanceof BrokenPerson)) return false;
            return name.equals(((BrokenPerson) o).name);
        }
        // hashCode() NOT overridden - uses Object's default (memory address based)
    }

    static class Person {
        String name;
        Person(String name) { this.name = name; }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof Person)) return false;
            return name.equals(((Person) o).name);
        }

        @Override
        public int hashCode() {
            return Objects.hash(name); // same field used in equals()
        }
    }

    public static void main(String[] args) {
        Set<BrokenPerson> brokenSet = new HashSet<>();
        brokenSet.add(new BrokenPerson("Alice"));
        brokenSet.add(new BrokenPerson("Alice")); // logically equal, but...
        System.out.println("Broken set size: " + brokenSet.size()); // 2 - duplicate not detected!

        Set<Person> goodSet = new HashSet<>();
        goodSet.add(new Person("Alice"));
        goodSet.add(new Person("Alice")); // same content, same hashCode
        System.out.println("Correct set size: " + goodSet.size()); // 1 - duplicate correctly rejected
    }
}

public class TextBlockDemo {
    public static void main(String[] args) {

        // Old style - messy escaping and concatenation
        String oldJson = "{\n" +
                          "  \"name\": \"Alice\",\n" +
                          "  \"age\": 30\n" +
                          "}";

        // New style - text block
        String newJson = """
