}

public class SwitchDemo {

    enum Day { MON, TUE, WED, THU, FRI, SAT, SUN }

    // Old style - fall-through risk, no direct value
    static String oldStyleType(Day day) {
        String type;
        switch (day) {
            case SAT:
            case SUN:
                type = "Weekend";
                break; // forgetting this would fall through!
            default:
                type = "Weekday";
        }
        return type;
    }

    // New style - switch expression, arrow syntax, no fall-through
    static String dayType(Day day) {
        return switch (day) {
            case SAT, SUN -> "Weekend";
            default -> "Weekday";
        };
    }

    // yield for multi-statement branches
    static int dayNumber(Day day) {
        return switch (day) {
            case MON -> 1;
            case TUE -> 2;
            default -> {
                System.out.println("Computing for: " + day);
                yield 0; // yield provides the branch's result
            }
        };
    }

    // Pattern matching switch (Java 21+) on sealed types
    sealed interface Shape permits Circle, Square {}
    record Circle(double radius) implements Shape {}
    record Square(double side) implements Shape {}

    static double area(Shape shape) {
        return switch (shape) {
            case Circle c -> Math.PI * c.radius() * c.radius();
            case Square s -> s.side() * s.side();
        }; // exhaustive - no default needed since all Shape subtypes are covered
    }

    public static void main(String[] args) {
        System.out.println(dayType(Day.SAT));      // Weekend
        System.out.println(dayNumber(Day.WED));     // 0 (with printed message)
        System.out.println(area(new Circle(2)));    // 12.566...
    }
}

public class CloneDemo {

    static class Address {
        String city;
        Address(String city) { this.city = city; }
    }

    static class ShallowPerson implements Cloneable {
        String name;
        Address address; // reference type

        ShallowPerson(String name, Address address) {
            this.name = name;
            this.address = address;
        }

        @Override
        public ShallowPerson clone() throws CloneNotSupportedException {
            return (ShallowPerson) super.clone(); // shallow - shares the same Address object
        }
    }

    static class DeepPerson implements Cloneable {
        String name;
        Address address;

        DeepPerson(String name, Address address) {
            this.name = name;
            this.address = address;
        }

        @Override
        public DeepPerson clone() throws CloneNotSupportedException {
            DeepPerson copy = (DeepPerson) super.clone();
            copy.address = new Address(this.address.city); // deep - clone the nested object too
            return copy;
        }
    }

    public static void main(String[] args) throws CloneNotSupportedException {
        ShallowPerson original = new ShallowPerson("Alice", new Address("Delhi"));
        ShallowPerson shallowClone = original.clone();
        shallowClone.address.city = "Mumbai"; // mutate through the clone
        System.out.println("Shallow - original city: " + original.address.city); // Mumbai! Bug.

        DeepPerson originalDeep = new DeepPerson("Bob", new Address("Delhi"));
        DeepPerson deepClone = originalDeep.clone();
        deepClone.address.city = "Mumbai";
        System.out.println("Deep - original city: " + originalDeep.address.city); // Delhi - unaffected

        // Modern alternative: copy constructor instead of clone()
        // class Person { Person(Person other) { this.name = other.name; this.address = new Address(other.address.city); } }
    }
}

