public class SolidDemo {

    // Dependency Inversion + Open/Closed: depend on an abstraction, not a concrete class
    interface PaymentProcessor {
        void pay(double amount);
    }

    static class CreditCardProcessor implements PaymentProcessor {
        public void pay(double amount) {
            System.out.println("Paid $" + amount + " via Credit Card");
        }
    }

    static class PayPalProcessor implements PaymentProcessor {
        public void pay(double amount) {
            System.out.println("Paid $" + amount + " via PayPal");
        }
    }

    // High-level class depends on the PaymentProcessor abstraction (DIP)
    // Adding a new payment method means adding a new class, not editing this one (OCP)
    static class CheckoutService {
        private final PaymentProcessor processor;

        CheckoutService(PaymentProcessor processor) { // injected dependency
            this.processor = processor;
        }

        void checkout(double amount) {
            processor.pay(amount);
        }
    }

    // Interface Segregation: small, focused interfaces instead of one bloated interface
    interface Workable { void work(); }
    interface Eatable { void eat(); }

    static class HumanWorker implements Workable, Eatable {
        public void work() { System.out.println("Working"); }
        public void eat() { System.out.println("Eating lunch"); }
    }

    static class RobotWorker implements Workable { // doesn't need eat() - not forced to implement it
        public void work() { System.out.println("Working without breaks"); }
    }

    public static void main(String[] args) {
        CheckoutService checkout1 = new CheckoutService(new CreditCardProcessor());
        checkout1.checkout(50.0);

        CheckoutService checkout2 = new CheckoutService(new PayPalProcessor());
        checkout2.checkout(25.0);
    }
}

import java.util.*;

public class RelationshipsDemo {

    static class Teacher {
        String name;
        Teacher(String name) { this.name = name; }
    }

    // Aggregation: Department HAS Teachers, but doesn't create or own their lifecycle
    static class Department {
        String name;
        List<Teacher> teachers; // injected from outside - teachers exist independently

        Department(String name, List<Teacher> teachers) {
            this.name = name;
            this.teachers = teachers; // not created here, just referenced
        }
    }

    static class Engine {
        String type;
        Engine(String type) { this.type = type; }
    }

    // Composition: Car HAS-AND-OWNS an Engine - it creates its own engine internally
    static class Car {
        String model;
        Engine engine; // strongly owned - created and destroyed with the Car

        Car(String model) {
            this.model = model;
            this.engine = new Engine("V6"); // engine is created here, tied to this car's lifecycle
        }
    }

    public static void main(String[] args) {
        // Aggregation example - teachers exist before and after the department
        Teacher t1 = new Teacher("Mr. Sharma");
        Teacher t2 = new Teacher("Ms. Iyer");
        Department cs = new Department("Computer Science", new ArrayList<>(List.of(t1, t2)));
        // Even if 'cs' is discarded, t1 and t2 still exist and could join another department

        // Composition example - the engine has no independent existence outside this Car
        Car myCar = new Car("Sedan");
        System.out.println(myCar.model + " has a " + myCar.engine.type + " engine");
        // When myCar is garbage collected, its engine has no meaningful separate reference left
    }
}

public class DiamondDemo {

    interface Greetable {
        default String greet() {
            return "Hello from Greetable";
        }
    }

    interface Welcomable {
        default String greet() {
            return "Hello from Welcomable";
        }
    }

    // Implementing both interfaces with conflicting default methods forces resolution
    static class Greeter implements Greetable, Welcomable {
        // Without overriding greet(), this class would NOT COMPILE:
        // "class Greeter inherits unrelated defaults for greet() from types Greetable and Welcomable"

        @Override
        public String greet() {
            // Explicitly choose which interface's implementation to use, or combine them
            return Greetable.super.greet() + " AND " + Welcomable.super.greet();
        }
    }

    public static void main(String[] args) {
        Greeter g = new Greeter();
        System.out.println(g.greet());
        // Hello from Greetable AND Hello from Welcomable
    }
}

import java.sql.SQLException;

public class ExceptionChainingDemo {

    // Custom domain-specific exception
    static class ServiceException extends RuntimeException {
        public ServiceException(String message, Throwable cause) {
            super(message, cause); // preserves the original cause
        }
    }

    static void queryDatabase() throws SQLException {
        throw new SQLException("Connection refused on port 5432");
    }

    static void fetchUser() {
        try {
            queryDatabase();
        } catch (SQLException e) {
            // GOOD: wrap with chaining - original exception preserved as cause
            throw new ServiceException("Failed to fetch user from database", e);

            // BAD (commented out) - loses the original stack trace and type entirely:
            // throw new RuntimeException("Failed to fetch user: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        try {
            fetchUser();
        } catch (ServiceException e) {
            System.out.println("Caught: " + e.getMessage());
            System.out.println("Root cause: " + e.getCause()); // SQLException: Connection refused...
            e.printStackTrace();
            // Output includes:
            // ServiceException: Failed to fetch user from database
            //   at ...
            // Caused by: java.sql.SQLException: Connection refused on port 5432
            //   at ...
        }
    }
}

public class ErrorVsExceptionDemo {

    // Checked Exception - must be declared or caught
    static void readFile() throws java.io.IOException {
        throw new java.io.IOException("File not found");
    }

    // Unchecked Exception (RuntimeException) - programming bug, not required to be declared
    static void divide(int a, int b) {
        if (b == 0) {
            throw new ArithmeticException("Cannot divide by zero");
        }
        System.out.println(a / b);
    }

    // Error - serious JVM-level problem, generally should NOT be caught in real applications
    static void causeStackOverflow() {
        causeStackOverflow(); // infinite recursion
    }

    public static void main(String[] args) {
        // Handling a checked Exception - expected and recoverable
        try {
            readFile();
        } catch (java.io.IOException e) {
            System.out.println("Recovered from: " + e.getMessage());
        }

        // Handling an unchecked Exception
        try {
            divide(10, 0);
        } catch (ArithmeticException e) {
            System.out.println("Recovered from: " + e.getMessage());
        }

        // Catching an Error - shown here only for demonstration; not recommended in real applications
        try {
            causeStackOverflow();
        } catch (StackOverflowError e) {
            System.out.println("Caught an Error (not typical practice): " + e.getClass().getSimpleName());
        }

        // Bad practice (commented): catching Throwable broadly hides both Errors and Exceptions indiscriminately
        // try { ... } catch (Throwable t) { ... }
    }
}

import java.util.*;
import java.util.concurrent.CopyOnWriteArrayList;

public class FailFastFailSafeDemo {
    public static void main(String[] args) {

        // FAIL-FAST: ArrayList throws ConcurrentModificationException
        List<String> arrayList = new ArrayList<>(List.of("A", "B", "C"));
        try {
            for (String item : arrayList) {
                if (item.equals("B")) {
                    arrayList.remove(item); // structural modification during iteration
                }
            }
        } catch (ConcurrentModificationException e) {
            System.out.println("Fail-fast: ConcurrentModificationException thrown!");
        }

        // SAFE FIX: use the iterator's own remove() method
        List<String> arrayList2 = new ArrayList<>(List.of("A", "B", "C"));
        Iterator<String> it = arrayList2.iterator();
        while (it.hasNext()) {
            if (it.next().equals("B")) {
                it.remove(); // safe - uses the iterator's own remove
            }
        }
        System.out.println("After safe removal: " + arrayList2);

        // FAIL-SAFE: CopyOnWriteArrayList does NOT throw, iterates over a snapshot
        List<String> cowList = new CopyOnWriteArrayList<>(List.of("A", "B", "C"));
        for (String item : cowList) {
            if (item.equals("B")) {
                cowList.remove(item); // no exception - iterator works on a snapshot
            }
        }
        System.out.println("CopyOnWriteArrayList after modification: " + cowList); // [A, C]
    }
}

import java.util.*;

public class PriorityQueueDemo {

    record Task(String name, int priority) {}

    public static void main(String[] args) {

        // Natural ordering - min-heap by default for Integers
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        minHeap.addAll(List.of(5, 1, 4, 2, 3));
        System.out.print("Polling order (min-heap): ");
        while (!minHeap.isEmpty()) {
            System.out.print(minHeap.poll() + " "); // 1 2 3 4 5 - always smallest first
        }
        System.out.println();

        // Max-heap using a reversed comparator
        PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Comparator.reverseOrder());
        maxHeap.addAll(List.of(5, 1, 4, 2, 3));
        System.out.print("Polling order (max-heap): ");
        while (!maxHeap.isEmpty()) {
            System.out.print(maxHeap.poll() + " "); // 5 4 3 2 1
        }
        System.out.println();

        // Custom objects with a Comparator - lower priority number = served first
        PriorityQueue<Task> taskQueue = new PriorityQueue<>(Comparator.comparingInt(Task::priority));
        taskQueue.offer(new Task("Low importance", 3));
        taskQueue.offer(new Task("Critical bug", 1));
        taskQueue.offer(new Task("Medium task", 2));

        System.out.println("Tasks in priority order:");
        while (!taskQueue.isEmpty()) {
            System.out.println("  " + taskQueue.poll().name());
        }
        // Critical bug, Medium task, Low importance

        // Important gotcha: iteration order is NOT sorted, only poll() order is guaranteed
        PriorityQueue<Integer> demo = new PriorityQueue<>(List.of(5, 1, 4, 2, 3));
        System.out.println("Raw iteration (not sorted!): " + demo); // heap array order, not 1,2,3,4,5
    }
}

import java.util.*;
import java.util.concurrent.CopyOnWriteArrayList;

public class CopyOnWriteDemo {
    public static void main(String[] args) throws InterruptedException {

        // Demonstrating safe concurrent iteration + modification
        CopyOnWriteArrayList<String> listeners = new CopyOnWriteArrayList<>();
        listeners.add("Listener-A");
        listeners.add("Listener-B");
        listeners.add("Listener-C");

        Thread reader = new Thread(() -> {
            for (String listener : listeners) { // iterates a stable snapshot
                System.out.println("Notifying: " + listener);
                try { Thread.sleep(50); } catch (InterruptedException ignored) {}
            }
        });

        Thread writer = new Thread(() -> {
            try { Thread.sleep(20); } catch (InterruptedException ignored) {}
            listeners.add("Listener-D"); // safe - does NOT throw ConcurrentModificationException
            System.out.println("Added Listener-D during iteration");
        });

        reader.start();
        writer.start();
        reader.join();
        writer.join();

        System.out.println("Final list: " + listeners); // includes Listener-D after the fact

        // Compare: a regular ArrayList in this same scenario would risk
        // ConcurrentModificationException if modified by another thread mid-iteration.

        // Collections.synchronizedList wraps method calls but iteration still needs manual locking:
        List<String> syncList = Collections.synchronizedList(new ArrayList<>(List.of("X", "Y")));
        synchronized (syncList) { // manual lock required for safe iteration
            for (String item : syncList) {
                System.out.println(item);
            }
        }
    }
}

import java.util.concurrent.*;

public class ThreadRunnableCallableDemo {

    // 1. Extending Thread directly
    static class MyThread extends Thread {
        @Override
        public void run() {
            System.out.println("Running via extended Thread");
        }
    }

    public static void main(String[] args) throws Exception {

        // Using Thread subclass
        new MyThread().start();

        // 2. Implementing Runnable - task decoupled from execution mechanism, no return value
        Runnable task = () -> System.out.println("Running via Runnable");
        Thread t = new Thread(task);
        t.start();

        ExecutorService executor = Executors.newFixedThreadPool(2);
        executor.submit(task); // same Runnable, reused with an executor

        // 3. Implementing Callable - returns a value via Future, can throw checked exceptions
        Callable<Integer> callableTask = () -> {
            Thread.sleep(100); // simulate work
            return 42;
        };

        Future<Integer> future = executor.submit(callableTask);
        System.out.println("Doing other work while task computes...");
        Integer result = future.get(); // blocks until result is ready
        System.out.println("Callable result: " + result);

        executor.shutdown();
    }
}

import java.text.SimpleDateFormat;
import java.util.concurrent.*;

public class ThreadLocalDemo {

    // SimpleDateFormat is NOT thread-safe - give each thread its own instance
    static final ThreadLocal<SimpleDateFormat> dateFormatHolder =
            ThreadLocal.withInitial(() -> new SimpleDateFormat("yyyy-MM-dd HH:mm:ss"));

    static String formatNow() {
        return dateFormatHolder.get().format(new java.util.Date());
    }

    public static void main(String[] args) throws InterruptedException {
        ExecutorService executor = Executors.newFixedThreadPool(3);

        for (int i = 0; i < 5; i++) {
            executor.submit(() -> {
                try {
                    String formatted = formatNow(); // each thread uses its own SimpleDateFormat safely
                    System.out.println(Thread.currentThread().getName() + ": " + formatted);
                } finally {
                    dateFormatHolder.remove(); // CRITICAL in pooled environments - prevents leaks/stale data
                }
            });
        }

        executor.shutdown();
        executor.awaitTermination(2, TimeUnit.SECONDS);

        // Per-request context example pattern (e.g. web server)
        ThreadLocal<String> requestId = new ThreadLocal<>();
        requestId.set("req-12345");
        System.out.println("Current request ID: " + requestId.get());
        requestId.remove(); // always clean up, especially in thread-pooled servers
    }
}

import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.*;

public class AtomicCASDemo {
    public static void main(String[] args) throws InterruptedException {

        // Unsafe counter - race condition with plain int
        int[] unsafeCounter = {0};

        // Safe counter using AtomicInteger - no synchronized needed
        AtomicInteger atomicCounter = new AtomicInteger(0);

        ExecutorService executor = Executors.newFixedThreadPool(4);
        int incrementsPerThread = 1000;

        Runnable task = () -> {
            for (int i = 0; i < incrementsPerThread; i++) {
                unsafeCounter[0]++;             // NOT thread-safe - lost updates likely
                atomicCounter.incrementAndGet(); // thread-safe via internal CAS loop
            }
        };

        Future<?> f1 = executor.submit(task);
        Future<?> f2 = executor.submit(task);
        Future<?> f3 = executor.submit(task);
        Future<?> f4 = executor.submit(task);
        f1.get(); f2.get(); f3.get(); f4.get();

        System.out.println("Unsafe counter (expected 4000): " + unsafeCounter[0]); // likely less than 4000
        System.out.println("Atomic counter (expected 4000): " + atomicCounter.get()); // always exactly 4000

        // Manually demonstrating a CAS retry loop (similar to what incrementAndGet does internally)
        AtomicInteger manual = new AtomicInteger(5);
        int expected, updated;
        do {
            expected = manual.get();
            updated = expected + 10;
        } while (!manual.compareAndSet(expected, updated)); // retries if another thread interfered
        System.out.println("Manual CAS result: " + manual.get()); // 15

        executor.shutdown();
    }
}

public class ConcurrencyHazardsDemo {

    // 1. RACE CONDITION - shared mutable state without synchronization
    static int sharedCounter = 0;

    static void unsafeIncrement() {
        sharedCounter++; // NOT atomic: read, increment, write - can interleave badly across threads
    }

    // 2. DEADLOCK - circular wait between two locks acquired in different orders
    static final Object lockA = new Object();
    static final Object lockB = new Object();

    static void deadlockProneMethod1() {
        synchronized (lockA) {
            try { Thread.sleep(50); } catch (InterruptedException ignored) {}
            synchronized (lockB) { // waits for lockB, held by the other thread below
                System.out.println("Method1 acquired both locks");
            }
        }
    }

    static void deadlockProneMethod2() {
        synchronized (lockB) {
            try { Thread.sleep(50); } catch (InterruptedException ignored) {}
            synchronized (lockA) { // waits for lockA, held by the other thread above - DEADLOCK
                System.out.println("Method2 acquired both locks");
            }
        }
    }

    // FIX for the deadlock above: always acquire locks in the SAME consistent order in every method
    static void fixedMethod1() {
        synchronized (lockA) {
            synchronized (lockB) {
                System.out.println("Fixed method1 acquired both locks safely");
            }
        }
    }
    static void fixedMethod2() {
        synchronized (lockA) { // same order as fixedMethod1 - no circular wait possible
            synchronized (lockB) {
                System.out.println("Fixed method2 acquired both locks safely");
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        // Demonstrate the race condition
        Runnable incrementTask = () -> {
            for (int i = 0; i < 100_000; i++) unsafeIncrement();
        };
        Thread t1 = new Thread(incrementTask);
        Thread t2 = new Thread(incrementTask);
        t1.start(); t2.start();
        t1.join(); t2.join();
        System.out.println("Expected 200000, got: " + sharedCounter); // usually less - race condition

        // Run the FIXED (deadlock-free) version safely
        Thread f1 = new Thread(ConcurrencyHazardsDemo::fixedMethod1);
        Thread f2 = new Thread(ConcurrencyHazardsDemo::fixedMethod2);
        f1.start(); f2.start();
        f1.join(); f2.join();

        // NOTE: deadlockProneMethod1/2 are intentionally NOT run together here,
        // since doing so would hang the program forever, illustrating why
        // consistent lock ordering (as in the fixed versions) is essential.

        // Livelock and starvation are scheduling/timing phenomena that are hard to
        // reliably reproduce in a short demo, but conceptually:
        // - Livelock: two threads repeatedly detect contention and both back off
        //   and retry at the same moment, forever, without ever finishing.
        // - Starvation: a thread is repeatedly skipped over because other threads
        //   are continually given the lock/CPU first (e.g., an unfair lock policy).
    }
}

import java.util.stream.Stream;
import java.util.List;

public class ShortCircuitDemo {
    public static void main(String[] args) {

        // limit() makes an infinite stream usable
        Stream<Integer> infiniteEvens = Stream.iterate(0, n -> n + 2);
        List<Integer> firstFive = infiniteEvens.limit(5).toList();
        System.out.println(firstFive); // [0, 2, 4, 6, 8] - without limit(), this would hang forever

        // anyMatch() stops at the first match - demonstrated with peek()
        List<Integer> numbers = List.of(1, 3, 5, 8, 9, 11, 13);
        boolean hasEven = numbers.stream()
                .peek(n -> System.out.println("Checking: " + n))
                .anyMatch(n -> n % 2 == 0);
        System.out.println("Has even number: " + hasEven);
        // Output stops checking immediately after finding 8 - elements after it are never examined

        // findFirst() on a filtered infinite stream - only computes as much as needed
        var firstBigSquare = Stream.iterate(1, n -> n + 1)
                .map(n -> n * n)
                .filter(square -> square > 50)
                .findFirst();
        System.out.println("First square > 50: " + firstBigSquare.get()); // 64

        // allMatch() stops at the first failure
        boolean allPositive = numbers.stream()
                .peek(n -> System.out.println("allMatch checking: " + n))
                .allMatch(n -> n > 0);
        System.out.println("All positive: " + allPositive); // true - but it still had to check every element here
    }
}

public class ClassLoaderDemo {

    // A simple custom ClassLoader skeleton, normally overriding findClass()
    static class SimpleCustomClassLoader extends ClassLoader {
        SimpleCustomClassLoader(ClassLoader parent) {
            super(parent); // delegate to the given parent first
        }
        // In a real implementation, you'd override findClass(String name)
        // to read .class bytes from a custom source (file, network, database, etc.)
    }

    public static void main(String[] args) {

        // Bootstrap classes (java.lang.*) - loaded by the bootstrap loader (often shown as null)
        ClassLoader stringLoader = String.class.getClassLoader();
        System.out.println("String's loader: " + stringLoader); // null - bootstrap loader has no Java representation

        // Your own application class - loaded by the Application/System ClassLoader
        ClassLoader appLoader = ClassLoaderDemo.class.getClassLoader();
        System.out.println("App class loader: " + appLoader);

        // Walk up the parent delegation chain
        ClassLoader current = appLoader;
        while (current != null) {
            System.out.println("-> " + current);
            current = current.getParent();
        }
        System.out.println("-> Bootstrap ClassLoader (native, no Java object representation)");

        // The system class loader explicitly
        System.out.println("System loader: " + ClassLoader.getSystemClassLoader());

        // Demonstrate a custom loader delegating to the system loader as its parent
        SimpleCustomClassLoader custom = new SimpleCustomClassLoader(ClassLoader.getSystemClassLoader());
        System.out.println("Custom loader's parent: " + custom.getParent());
    }
}
